import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getListing, getContacts, getSimilarListings, registerView } from '../services/listings';
import PhotoGallery from '../components/PhotoGallery';
import ListingCard from '../components/ListingCard';
import Loader from '../components/Loader';
import ErrorMessage from '../components/ErrorMessage';
import { useAuth } from '../context/AuthContext';
import './ListingDetail.css';

function ListingDetail() {
  const { id } = useParams();
  const { user } = useAuth();

  const [listing, setListing] = useState(null);
  const [contacts, setContacts] = useState(null);
  const [similar, setSimilar] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showContacts, setShowContacts] = useState(false);

  useEffect(() => {
    loadListing();
    registerView(id, user?.user_id);
  }, [id]);

  const loadListing = async () => {
    setLoading(true);
    try {
      const [listingData, similarData] = await Promise.all([
        getListing(id),
        getSimilarListings(id)
      ]);

      setListing(listingData);
      setSimilar(similarData);
    } catch (err) {
      setError('Ошибка загрузки объявления');
    } finally {
      setLoading(false);
    }
  };

  const handleShowContacts = async () => {
    if (!user) {
      alert('Войдите чтобы увидеть контакты');
      return;
    }

    try {
      const data = await getContacts(id);
      setContacts(data);
      setShowContacts(true);
    } catch (err) {
      alert('Ошибка загрузки контактов');
    }
  };

  if (loading) return <Loader />;
  if (error) return <ErrorMessage message={error} />;
  if (!listing) return <ErrorMessage message="Объявление не найдено" />;

  return (
    <div className="listing-detail">
      <div className="listing-header">
        <h1>{listing.title}</h1>
        <Link to={`/user/${listing.user_id}`} className="seller-link">
          Смотреть все объявления продавца →
        </Link>
      </div>

      <div className="listing-content">
        <div className="listing-main">
          <PhotoGallery photos={listing.photos || []} />

          <div className="listing-info">
            <div className="price-section">
              <span className="price">{listing.price?.toLocaleString()} ₽</span>
              {listing.deal_type === 'rent' && <span className="per-month">/мес</span>}
            </div>

            <div className="details-grid">
              <div className="detail-item">
                <span className="detail-label">Адрес:</span>
                <span className="detail-value">{listing.address}</span>
              </div>
              <div className="detail-item">
                <span className="detail-label">Площадь:</span>
                <span className="detail-value">{listing.total_area} м²</span>
              </div>
              {listing.rooms && (
                <div className="detail-item">
                  <span className="detail-label">Комнат:</span>
                  <span className="detail-value">{listing.rooms}</span>
                </div>
              )}
              <div className="detail-item">
                <span className="detail-label">Дата публикации:</span>
                <span className="detail-value">
                  {new Date(listing.publication_date).toLocaleDateString()}
                </span>
              </div>
              <div className="detail-item">
                <span className="detail-label">Просмотров:</span>
                <span className="detail-value">{listing.views}</span>
              </div>
            </div>

            {listing.description && (
              <div className="description">
                <h3>Описание</h3>
                <p>{listing.description}</p>
              </div>
            )}
          </div>
        </div>

        <div className="listing-sidebar">
          <div className="contacts-card">
            <h3>Контакты</h3>

            {showContacts && contacts ? (
              <div className="contacts-info">
                <p className="contact-phone">📞 {contacts.phone}</p>
                {contacts.person && (
                  <p className="contact-person">👤 {contacts.person}</p>
                )}
              </div>
            ) : (
              <button onClick={handleShowContacts} className="show-contacts-btn">
                Показать телефон
              </button>
            )}

            <p className="contact-note">
              После показа телефона мы сообщим продавцу о вашем интересе
            </p>
          </div>
        </div>
      </div>

      {similar.length > 0 && (
        <div className="similar-listings">
          <h2>Похожие объявления</h2>
          <div className="similar-grid">
            {similar.map(item => (
              <ListingCard key={item.listing_id} listing={item} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default ListingDetail;
